// translated_0.cl - OpenCL kernels for streamcluster pgain computation

typedef struct {
    float weight;
    long assign;
    float cost;
} Point_Struct;

// Main pgain kernel - computes distances and updates work_mem and switch_membership
kernel void pgain_kernel(
    global Point_Struct* p,
    global float* coord,
    global float* work_mem,
    global int* center_table,
    global char* switch_membership,
    int num,
    int dim,
    long x,
    int K
) {
    int i = get_global_id(0);
    if (i >= num) return;

    // Calculate squared Euclidean distance from point i to point x
    float dist_sq = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[d * num + i] - coord[d * num + x];
        dist_sq += diff * diff;
    }

    float x_cost = dist_sq * p[i].weight;
    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        // Point i would benefit from switching to center x
        switch_membership[i] = 1;
        work_mem[i * (K + 1) + K] += x_cost - current_cost;
    } else {
        // Point i stays with current center
        int assign = p[i].assign;
        int ct = center_table[assign];
        work_mem[ct * (K + 1) + i] += current_cost - x_cost;
    }
}

// Kernel to initialize work_mem to zero
kernel void init_work_mem(
    global float* work_mem,
    int size
) {
    int i = get_global_id(0);
    if (i < size) {
        work_mem[i] = 0.0f;
    }
}

// Kernel to initialize switch_membership to zero
kernel void init_switch_membership(
    global char* switch_membership,
    int size
) {
    int i = get_global_id(0);
    if (i < size) {
        switch_membership[i] = 0;
    }
}

// Kernel to compute center_table from is_center
kernel void compute_center_table(
    global char* is_center,
    global int* center_table,
    int num
) {
    int i = get_global_id(0);
    if (i >= num) return;

    if (is_center[i] == 1) {
        int count = 0;
        for (int j = 0; j < i; j++) {
            if (is_center[j] == 1) {
                count++;
            }
        }
        center_table[i] = count;
    }
}

// Kernel to copy point data to Point_Struct format
kernel void copy_point_data(
    global Point_Struct* p_out,
    global float* weights,
    global long* assigns,
    global float* costs,
    int num
) {
    int i = get_global_id(0);
    if (i >= num) return;

    p_out[i].weight = weights[i];
    p_out[i].assign = assigns[i];
    p_out[i].cost = costs[i];
}

// Kernel to transpose coordinate data (row to column format for OpenCL)
kernel void transpose_coords(
    global float* coord_out,
    global float* coord_in,
    int num,
    int dim
) {
    int i = get_global_id(0);
    int d = get_global_id(1);

    if (i >= num || d >= dim) return;

    coord_out[d * num + i] = coord_in[i * dim + d];
}

// Kernel to update point costs and assignments after gain computation
kernel void update_points(
    global Point_Struct* p,
    global float* coord,
    global char* switch_membership,
    global float* gl_lower,
    global int* center_table,
    global char* is_center,
    long x,
    int num,
    int dim
) {
    int i = get_global_id(0);
    if (i >= num) return;

    int assign = p[i].assign;
    char close_center = gl_lower[center_table[assign]] > 0 ? 1 : 0;

    if (switch_membership[i] == 1 || close_center == 1) {
        // Calculate new cost
        float dist_sq = 0.0f;
        for (int d = 0; d < dim; d++) {
            float diff = coord[d * num + i] - coord[d * num + x];
            dist_sq += diff * diff;
        }
        p[i].cost = dist_sq * p[i].weight;
        p[i].assign = x;
    }

    if (is_center[i] == 1 && gl_lower[center_table[i]] > 0) {
        is_center[i] = 0;
    }

    if (i == x) {
        is_center[i] = 1;
    }
}
